package ahocorasick

// TrieNode represents a node in the Aho-Corasick automaton.
type TrieNode struct {
	children map[byte]int
	fail     int
	output   []int
}

// AhoCorasick is the string matching automaton.
type AhoCorasick struct {
	trie     []TrieNode
	patterns []string
}

// NewAhoCorasick builds the automaton from the given patterns.
func NewAhoCorasick(patterns []string) *AhoCorasick {
	ac := &AhoCorasick{
		patterns: patterns,
		trie:     []TrieNode{{children: make(map[byte]int), fail: 0}},
	}
	ac.buildTrie()
	ac.buildFailLinks()
	return ac
}

func (ac *AhoCorasick) buildTrie() {
	for i, pat := range ac.patterns {
		cur := 0
		for j := 0; j < len(pat); j++ {
			c := pat[j]
			if _, ok := ac.trie[cur].children[c]; !ok {
				ac.trie[cur].children[c] = len(ac.trie)
				ac.trie = append(ac.trie, TrieNode{children: make(map[byte]int)})
			}
			cur = ac.trie[cur].children[c]
		}
		ac.trie[cur].output = append(ac.trie[cur].output, i)
	}
}

func (ac *AhoCorasick) buildFailLinks() {
	queue := []int{}
	for _, child := range ac.trie[0].children {
		ac.trie[child].fail = 0
		queue = append(queue, child)
	}

	for len(queue) > 0 {
		u := queue[0]
		queue = queue[1:]
		for c, v := range ac.trie[u].children {
			f := ac.trie[u].fail
			for f != 0 {
				if _, ok := ac.trie[f].children[c]; ok {
					break
				}
				f = ac.trie[f].fail
			}
			if child, ok := ac.trie[f].children[c]; ok && child != v {
				ac.trie[v].fail = child
			} else {
				ac.trie[v].fail = 0
			}
			ac.trie[v].output = append(ac.trie[v].output, ac.trie[ac.trie[v].fail].output...)
			queue = append(queue, v)
		}
	}
}

// Match represents a pattern match with the pattern string and start index.
type Match struct {
	Pattern string
	Index   int
}

// Search finds all occurrences of patterns in the text.
func (ac *AhoCorasick) Search(text string) []Match {
	var results []Match
	cur := 0
	for i := 0; i < len(text); i++ {
		c := text[i]
		for cur != 0 {
			if _, ok := ac.trie[cur].children[c]; ok {
				break
			}
			cur = ac.trie[cur].fail
		}
		if child, ok := ac.trie[cur].children[c]; ok {
			cur = child
		}
		for _, idx := range ac.trie[cur].output {
			results = append(results, Match{
				Pattern: ac.patterns[idx],
				Index:   i - len(ac.patterns[idx]) + 1,
			})
		}
	}
	return results
}

import java.util.*;

public class AhoCorasick {
    private int[][] goTo;
    private int[] fail;
    private List<Integer>[] output;
    private String[] patterns;
    private int states;

    public AhoCorasick(String[] patterns) {
        this.patterns = patterns;
        int maxStates = 1;
        for (String p : patterns) maxStates += p.length();

        goTo = new int[maxStates][26];
        for (int[] row : goTo) Arrays.fill(row, -1);
        fail = new int[maxStates];
        output = new ArrayList[maxStates];
        for (int i = 0; i < maxStates; i++) output[i] = new ArrayList<>();

        states = 1;
        buildTrie();
        buildFailLinks();
    }

    private void buildTrie() {
        for (int i = 0; i < patterns.length; i++) {
            int cur = 0;
            for (char c : patterns[i].toCharArray()) {
                int ch = c - 'a';
                if (goTo[cur][ch] == -1) {
                    goTo[cur][ch] = states++;
                }
                cur = goTo[cur][ch];
            }
            output[cur].add(i);
        }
    }

    private void buildFailLinks() {
        Queue<Integer> queue = new LinkedList<>();
        for (int c = 0; c < 26; c++) {
            if (goTo[0][c] != -1) {
                fail[goTo[0][c]] = 0;
                queue.add(goTo[0][c]);
            } else {
                goTo[0][c] = 0;
            }
        }

        while (!queue.isEmpty()) {
            int u = queue.poll();
            for (int c = 0; c < 26; c++) {
                if (goTo[u][c] != -1) {
                    int v = goTo[u][c];
                    int f = fail[u];
                    while (f != 0 && goTo[f][c] == -1) f = fail[f];
                    fail[v] = (goTo[f][c] != -1 && goTo[f][c] != v) ? goTo[f][c] : 0;
                    output[v].addAll(output[fail[v]]);
                    queue.add(v);
                }
            }
        }
    }

    public List<int[]> search(String text) {
        List<int[]> results = new ArrayList<>();
        int cur = 0;
        for (int i = 0; i < text.length(); i++) {
            int c = text.charAt(i) - 'a';
            while (cur != 0 && goTo[cur][c] == -1) cur = fail[cur];
            if (goTo[cur][c] != -1) cur = goTo[cur][c];
            for (int idx : output[cur]) {
                results.add(new int[]{idx, i - patterns[idx].length() + 1});
            }
        }
        return results;
    }

    public static List<List<Object>> ahoCorasickSearch(String text, String[] patterns) {
        List<List<Object>> result = new ArrayList<>();
        for (int end = 0; end < text.length(); end++) {
            for (String pattern : patterns) {
                int length = pattern.length();
                int start = end - length + 1;
                if (start < 0) {
                    continue;
                }
                if (text.regionMatches(start, pattern, 0, length)) {
                    result.add(Arrays.asList(pattern, start));
                }
            }
        }
        return result;
    }

    public static void main(String[] args) {
        String[] patterns = {"he", "she", "his", "hers"};
        AhoCorasick ac = new AhoCorasick(patterns);
        List<int[]> results = ac.search("ahishers");
        for (int[] r : results) {
            System.out.println("Word \"" + patterns[r[0]] + "\" found at index " + r[1]);
        }
    }
}

import java.util.LinkedList

fun ahoCorasickSearch(text: String, patternsLine: String): List<List<Any>> {
    val patterns = patternsLine.split(" ").filter { it.isNotEmpty() }
    val patternOrder = patterns.withIndex().associate { it.value to it.index }
    return AhoCorasick(patterns.toTypedArray())
        .search(text)
        .sortedWith(
            compareBy<Pair<String, Int>>(
                { it.second + it.first.length - 1 },
                { patternOrder[it.first] ?: Int.MAX_VALUE },
            ),
        )
        .map { (word, index) -> listOf(word, index) }
}

class AhoCorasick(private val patterns: Array<String>) {
    private val goTo: Array<IntArray>
    private val fail: IntArray
    private val output: Array<MutableList<Int>>
    private var states: Int = 1

    init {
        val maxStates = patterns.sumOf { it.length } + 1
        goTo = Array(maxStates) { IntArray(26) { -1 } }
        fail = IntArray(maxStates)
        output = Array(maxStates) { mutableListOf() }
        buildTrie()
        buildFailLinks()
    }

    private fun buildTrie() {
        for (i in patterns.indices) {
            var cur = 0
            for (c in patterns[i]) {
                val ch = c - 'a'
                if (goTo[cur][ch] == -1) {
                    goTo[cur][ch] = states++
                }
                cur = goTo[cur][ch]
            }
            output[cur].add(i)
        }
    }

    private fun buildFailLinks() {
        val queue = LinkedList<Int>()
        for (c in 0 until 26) {
            if (goTo[0][c] != -1) {
                fail[goTo[0][c]] = 0
                queue.add(goTo[0][c])
            } else {
                goTo[0][c] = 0
            }
        }
        while (queue.isNotEmpty()) {
            val u = queue.poll()
            for (c in 0 until 26) {
                if (goTo[u][c] != -1) {
                    val v = goTo[u][c]
                    var f = fail[u]
                    while (f != 0 && goTo[f][c] == -1) f = fail[f]
                    fail[v] = if (goTo[f][c] != -1 && goTo[f][c] != v) goTo[f][c] else 0
                    output[v].addAll(output[fail[v]])
                    queue.add(v)
                }
            }
        }
    }

    fun search(text: String): List<Pair<String, Int>> {
        val results = mutableListOf<Pair<String, Int>>()
        var cur = 0
        for (i in text.indices) {
            val ch = text[i].lowercaseChar()
            if (ch !in 'a'..'z') {
                cur = 0
                continue
            }
            val c = ch - 'a'
            while (cur != 0 && goTo[cur][c] == -1) cur = fail[cur]
            if (goTo[cur][c] != -1) cur = goTo[cur][c]
            for (idx in output[cur]) {
                results.add(Pair(patterns[idx], i - patterns[idx].length + 1))
            }
        }
        return results
    }
}

