use std::collections::HashMap;
use std::collections::VecDeque;

struct TrieNode {
    children: HashMap<u8, usize>,
    fail: usize,
    output: Vec<usize>,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode {
            children: HashMap::new(),
            fail: 0,
            output: Vec::new(),
        }
    }
}

struct AhoCorasick {
    trie: Vec<TrieNode>,
    patterns: Vec<String>,
}

impl AhoCorasick {
    fn new(patterns: Vec<String>) -> Self {
        let mut ac = AhoCorasick {
            trie: vec![TrieNode::new()],
            patterns,
        };
        ac.build_trie();
        ac.build_fail_links();
        ac
    }

    fn build_trie(&mut self) {
        for i in 0..self.patterns.len() {
            let mut cur = 0;
            for &b in self.patterns[i].as_bytes() {
                let next = self.trie.len();
                let entry = self.trie[cur].children.entry(b).or_insert(next);
                if *entry == next {
                    self.trie.push(TrieNode::new());
                }
                cur = *entry;
            }
            self.trie[cur].output.push(i);
        }
    }

    fn build_fail_links(&mut self) {
        let mut queue = VecDeque::new();
        let root_children: Vec<(u8, usize)> = self.trie[0].children.iter()
            .map(|(&k, &v)| (k, v)).collect();
        for (_, child) in root_children {
            self.trie[child].fail = 0;
            queue.push_back(child);
        }

        while let Some(u) = queue.pop_front() {
            let children: Vec<(u8, usize)> = self.trie[u].children.iter()
                .map(|(&k, &v)| (k, v)).collect();
            for (c, v) in children {
                let mut f = self.trie[u].fail;
                while f != 0 && !self.trie[f].children.contains_key(&c) {
                    f = self.trie[f].fail;
                }
                let fail_target = if let Some(&fc) = self.trie[f].children.get(&c) {
                    if fc != v { fc } else { 0 }
                } else {
                    0
                };
                self.trie[v].fail = fail_target;
                let fail_output: Vec<usize> = self.trie[fail_target].output.clone();
                self.trie[v].output.extend(fail_output);
                queue.push_back(v);
            }
        }
    }

    fn search(&self, text: &str) -> Vec<(String, usize)> {
        let mut results = Vec::new();
        let mut cur = 0;
        for (i, &b) in text.as_bytes().iter().enumerate() {
            while cur != 0 && !self.trie[cur].children.contains_key(&b) {
                cur = self.trie[cur].fail;
            }
            if let Some(&next) = self.trie[cur].children.get(&b) {
                cur = next;
            }
            for &idx in &self.trie[cur].output {
                results.push((self.patterns[idx].clone(), i + 1 - self.patterns[idx].len()));
            }
        }
        results
    }
}

fn main() {
    let patterns = vec![
        "he".to_string(), "she".to_string(),
        "his".to_string(), "hers".to_string(),
    ];
    let ac = AhoCorasick::new(patterns);
    let results = ac.search("ahishers");
    for (word, index) in &results {
        println!("Word \"{}\" found at index {}", word, index);
    }
}

import scala.collection.mutable

object AhoCorasick {
  class TrieNode {
    val children: mutable.Map[Char, Int] = mutable.Map()
    var fail: Int = 0
    val output: mutable.ListBuffer[Int] = mutable.ListBuffer()
  }

  class Automaton(patterns: Array[String]) {
    private val trie: mutable.ArrayBuffer[TrieNode] = mutable.ArrayBuffer(new TrieNode)

    buildTrie()
    buildFailLinks()

    private def buildTrie(): Unit = {
      for (i <- patterns.indices) {
        var cur = 0
        for (c <- patterns(i)) {
          if (!trie(cur).children.contains(c)) {
            trie(cur).children(c) = trie.size
            trie += new TrieNode
          }
          cur = trie(cur).children(c)
        }
        trie(cur).output += i
      }
    }

    private def buildFailLinks(): Unit = {
      val queue = mutable.Queue[Int]()
      for ((_, child) <- trie(0).children) {
        trie(child).fail = 0
        queue.enqueue(child)
      }
      while (queue.nonEmpty) {
        val u = queue.dequeue()
        for ((c, v) <- trie(u).children) {
